// Parse the Sheets API response into row objects
const { values } = $input.first().json;
if (!values || values.length < 2) return [];

const headers = values[0];
return values
  .slice(1)
  .map((row, idx) => ({
    json: {
      ...Object.fromEntries(headers.map((h, j) => [h, row[j] ?? ''])),
      row_number: idx + 2  // 1-indexed; row 1 is header
    }
  }))
  .filter(item => item.json['Leads Company Name'] !== '');

const row = $input.item.json;

const stageMap = [
  { col: 'Live?',              stage: 'live_client'   },
  { col: 'Activated?',         stage: 'activated'     },
  { col: 'Final Test?',        stage: 'final_testing' },
  { col: 'Setting Up?',        stage: 'onboarding'    },
  { col: 'Approved?',          stage: 'approved'      },
  { col: 'Quoted?',            stage: 'quoted'        },
  { col: 'Document Sent?',     stage: 'document_sent' },
  { col: 'Sales Call Booked?', stage: 'call_booked'   },
];

let currentStage = 'call_booked';
for (const { col, stage } of stageMap) {
  if ((row[col] || '').toString().toLowerCase().trim() === 'yes') {
    currentStage = stage;
    break;
  }
}

const status = (row['Status?'] || '').toString().toLowerCase().trim();
if (status === 'lost')   currentStage = 'closed_lost';
if (status === 'paused') currentStage = 'paused';

const rawValue = row['Deal Value ($)'];
const dealValue = rawValue && rawValue.toString().trim() !== '' && rawValue.toString().trim() !== 'N/A'
  ? parseFloat(rawValue.toString().replace(/[^0-9.]/g, ''))
  : null;

const invoiceUrl = row['Invoice URL'] && row['Invoice URL'].toString().trim() !== ''
  ? row['Invoice URL'].toString().trim() : null;

const jobUrl = row['Job Url'] && row['Job Url'] !== 'N/A' ? row['Job Url'] : null;
const scrapedFrom = row['Scraped From'] && row['Scraped From'] !== 'N/A' ? row['Scraped From'] : null;
const rowId = String(row['row_number']);

const clientBody = JSON.stringify({
  company_name:  row['Leads Company Name'],
  contact_name:  row['Contact Name'] || null,
  job_advert_url: jobUrl,
  scraped_from:  scrapedFrom,
  notes:         row['Notes'] || null,
  sheet_row_id:  rowId
});

return {
  json: {
    ...row,
    _stage:      currentStage,
    _dealValue:  dealValue,
    _invoiceUrl: invoiceUrl,
    _rowId:      rowId,
    _clientBody: clientBody,
  }
};
